/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Formats notification payloads as SMS messages (subject + body, truncated to 160 chars)
 * - Sends to a validated phone number
 * - Pluggable transport: supports swappable SMS providers (Twilio, in-memory for tests)
 *
 * Architecture: Implements NotificationAdapter interface. Registered with
 * NotificationService via registerAdapter(). All SMS delivery flows through
 * the EventBus → NotificationService → SmsAdapter pipeline.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/** Maximum length for a single SMS message. */
export const SMS_MAX_LENGTH = 160;

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  body: string;
}

/**
 * Pluggable transport interface for SMS delivery.
 * Implement this for Twilio, AWS SNS, or testing.
 */
export interface SmsTransport {
  send(message: SmsMessage): Promise<void>;
}

/**
 * In-memory transport that captures SMS messages for testing.
 */
export class InMemorySmsTransport implements SmsTransport {
  private messages: SmsMessage[] = [];

  async send(message: SmsMessage): Promise<void> {
    this.messages.push(message);
  }

  getMessages(): SmsMessage[] {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

export interface SmsConfig {
  /** SMS transport (defaults to InMemorySmsTransport) */
  transport?: SmsTransport;
}

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

/**
 * Validate and normalize a phone number.
 * Expects E.164 format: +{country code}{number} (e.g. +14155551234).
 * @throws Error if the phone number is not valid E.164
 */
export function validatePhoneNumber(phone: string): string {
  const trimmed = phone.trim();
  if (!PHONE_REGEX.test(trimmed)) {
    throw new Error(`Invalid phone number (expected E.164 format): ${phone}`);
  }
  return trimmed;
}

/**
 * Format a NotificationPayload into an SMS message body.
 * Truncates to SMS_MAX_LENGTH characters.
 */
export function formatSmsMessage(payload: NotificationPayload): string {
  const full = `${payload.subject}: ${payload.body}`;
  if (full.length <= SMS_MAX_LENGTH) {
    return full;
  }
  return full.slice(0, SMS_MAX_LENGTH - 3) + '...';
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;

  constructor(private config: SmsConfig = {}) {
    this.transport = config.transport ?? new InMemorySmsTransport();
  }

  /**
   * Send a notification via SMS.
   * Validates the recipient phone number and sends the formatted message.
   * @param payload - The notification to deliver
   * @throws Error if the phone number is invalid or the transport fails
   */
  async send(payload: NotificationPayload): Promise<void> {
    const to = validatePhoneNumber(payload.recipient);
    const body = formatSmsMessage(payload);

    await this.transport.send({ to, body });
    this.logger.info(`SMS sent to ${to}: ${payload.id}`);
  }

  /**
   * Get the transport (for testing access to InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }

  /**
   * Convenience: get sent messages when using InMemorySmsTransport.
   * @throws Error if transport is not InMemorySmsTransport
   */
  getSentMessages(): SmsMessage[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getMessages();
    }
    throw new Error('getSentMessages() is only available with InMemorySmsTransport');
  }

  /**
   * Convenience: clear sent messages when using InMemorySmsTransport.
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  validatePhoneNumber,
  formatSmsMessage,
  SMS_MAX_LENGTH,
} from '../../src/adapters/sms.adapter.js';
import type { SmsTransport, SmsMessage } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'sms',
    recipient: '+14155551234',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    metadata: {
      orderId: 'order-1',
      userId: 'user-1',
      items: [{ name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
    },
    createdAt: new Date('2026-01-15'),
    ...overrides,
  };
}

describe('validatePhoneNumber', () => {
  it('should accept valid E.164 phone numbers', () => {
    expect(validatePhoneNumber('+14155551234')).toBe('+14155551234');
  });

  it('should accept international numbers', () => {
    expect(validatePhoneNumber('+442071234567')).toBe('+442071234567');
  });

  it('should trim whitespace', () => {
    expect(validatePhoneNumber('  +14155551234  ')).toBe('+14155551234');
  });

  it('should reject numbers without + prefix', () => {
    expect(() => validatePhoneNumber('14155551234')).toThrow('Invalid phone number');
  });

  it('should reject empty strings', () => {
    expect(() => validatePhoneNumber('')).toThrow('Invalid phone number');
  });

  it('should reject numbers with letters', () => {
    expect(() => validatePhoneNumber('+1415555ABCD')).toThrow('Invalid phone number');
  });

  it('should reject numbers that are too short', () => {
    expect(() => validatePhoneNumber('+12345')).toThrow('Invalid phone number');
  });

  it('should reject numbers starting with +0', () => {
    expect(() => validatePhoneNumber('+0123456789')).toThrow('Invalid phone number');
  });
});

describe('formatSmsMessage', () => {
  it('should combine subject and body', () => {
    const payload = makePayload({
      subject: 'Order Update',
      body: 'Status changed.',
    });
    expect(formatSmsMessage(payload)).toBe('Order Update: Status changed.');
  });

  it('should truncate messages longer than SMS_MAX_LENGTH', () => {
    const payload = makePayload({
      subject: 'Order Confirmation',
      body: 'A'.repeat(200),
    });
    const result = formatSmsMessage(payload);
    expect(result.length).toBe(SMS_MAX_LENGTH);
    expect(result.endsWith('...')).toBe(true);
  });

  it('should not truncate short messages', () => {
    const payload = makePayload({
      subject: 'Hi',
      body: 'Done.',
    });
    const result = formatSmsMessage(payload);
    expect(result).toBe('Hi: Done.');
    expect(result.length).toBeLessThanOrEqual(SMS_MAX_LENGTH);
  });

  it('should handle exactly SMS_MAX_LENGTH message', () => {
    const subject = 'S';
    // "S: " = 3 chars, so body needs to be exactly 157 chars to hit 160
    const body = 'B'.repeat(SMS_MAX_LENGTH - 3);
    const payload = makePayload({ subject, body });
    const result = formatSmsMessage(payload);
    expect(result.length).toBe(SMS_MAX_LENGTH);
    expect(result.endsWith('...')).toBe(false);
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should capture messages', async () => {
    await transport.send({ to: '+14155551234', body: 'Hello' });

    const messages = transport.getMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0].to).toBe('+14155551234');
    expect(messages[0].body).toBe('Hello');
  });

  it('should return a copy of messages', async () => {
    await transport.send({ to: '+14155551234', body: 'Hello' });

    const m1 = transport.getMessages();
    const m2 = transport.getMessages();
    expect(m1).not.toBe(m2);
    expect(m1).toEqual(m2);
  });

  it('should clear messages', async () => {
    await transport.send({ to: '+14155551234', body: 'Hello' });
    transport.clear();
    expect(transport.getMessages()).toHaveLength(0);
  });
});

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  it('should have channel set to sms', () => {
    expect(adapter.channel).toBe('sms');
  });

  it('should send formatted SMS message', async () => {
    const payload = makePayload();
    await adapter.send(payload);

    const messages = transport.getMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0].to).toBe('+14155551234');
    expect(messages[0].body).toBe('Order Confirmation: Your order has been placed.');
  });

  it('should validate recipient phone number', async () => {
    const payload = makePayload({ recipient: 'not-a-phone' });
    await expect(adapter.send(payload)).rejects.toThrow('Invalid phone number');
  });

  it('should truncate long messages', async () => {
    const payload = makePayload({ body: 'X'.repeat(200) });
    await adapter.send(payload);

    const messages = transport.getMessages();
    expect(messages[0].body.length).toBe(SMS_MAX_LENGTH);
    expect(messages[0].body.endsWith('...')).toBe(true);
  });

  it('should handle all notification types', async () => {
    const types = ['order_confirmation', 'order_status_update', 'welcome', 'account_updated'] as const;

    for (const type of types) {
      await adapter.send(makePayload({ type }));
    }

    const messages = transport.getMessages();
    expect(messages).toHaveLength(4);
  });

  it('should propagate transport errors', async () => {
    const failingTransport: SmsTransport = {
      async send(): Promise<void> {
        throw new Error('SMS provider unavailable');
      },
    };

    const failAdapter = new SmsAdapter({ transport: failingTransport });
    await expect(failAdapter.send(makePayload())).rejects.toThrow('SMS provider unavailable');
  });

  it('should use InMemorySmsTransport by default', () => {
    const defaultAdapter = new SmsAdapter();
    expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemorySmsTransport);
  });

  it('should expose getSentMessages convenience method', async () => {
    await adapter.send(makePayload());
    const messages = adapter.getSentMessages();
    expect(messages).toHaveLength(1);
  });

  it('should throw getSentMessages when not using InMemorySmsTransport', () => {
    const customTransport: SmsTransport = {
      async send(): Promise<void> {},
    };
    const customAdapter = new SmsAdapter({ transport: customTransport });

    expect(() => customAdapter.getSentMessages()).toThrow(
      'getSentMessages() is only available with InMemorySmsTransport',
    );
  });

  it('should clear messages via convenience method', async () => {
    await adapter.send(makePayload());
    adapter.clearSentMessages();
    expect(adapter.getSentMessages()).toHaveLength(0);
  });
});

